    var content = document.getElementById('userMenuContent')
    if (!currentUser) {
        content.innerHTML = '<div class="text-center py-8 text-gray-400"><i class="fas fa-lock text-3xl mb-3"></i><p>Vui l\xF2ng \u0111\u0103ng nh\u1EADp \u0111\u1EC3 n\u1EA1p ti\u1EC1n</p></div>'
        return
    }
    var tc = 'QHVN90' + currentUser.userId
